import React, { useState, useEffect } from 'react';
import './App.css';

interface InventoryItem {
  id: number;
  account: string;
  type: string;
  quantity: number;
  proof: number;
  proofGallons: number;
  receivedDate: string;
  source: string;
  dspNumber: string;
}

interface ReportData {
  month?: string;
  date?: string;
  totalReceived: number;
  totalProcessed: number;
  totalMoved?: number;
  totalRemoved?: number;
  transactions?: { action: string; proofGallons: number; type: string; date: string }[];
}

const App: React.FC = () => {
  const [inventory, setInventory] = useState<InventoryItem[]>([]);
  const [form, setForm] = useState({
    account: 'Production',
    type: 'Cane Sugar',
    quantity: '',
    proof: '',
    source: '',
    dspNumber: 'DSP-AL-20010',
    receivedDate: new Date().toISOString().split('T')[0]
  });
  const [report, setReport] = useState<ReportData | null>(null);
  const [reportMonth, setReportMonth] = useState(new Date().toISOString().slice(0, 7));
  const [reportDate, setReportDate] = useState(new Date().toISOString().split('T')[0]);

  useEffect(() => {
    fetch('/api/inventory')
      .then(res => res.json())
      .then(data => setInventory(data));
  }, []);

  const handleReceive = async () => { /* unchanged */ };

  const fetchMonthlyReport = async () => {
    console.log('Fetching monthly report for:', reportMonth);
    try {
      const res = await fetch(`/api/report/monthly?month=${reportMonth}`);
      if (!res.ok) throw new Error(`Failed to fetch report: ${res.status}`);
      const data = await res.json();
      console.log('Monthly report data:', data);
      setReport(data);
    } catch (err: unknown) {
      console.error('Report error:', err);
      alert('Failed to fetch monthly report: ' + (err instanceof Error ? err.message : 'Unknown error'));
    }
  };

  const fetchDailyReport = async () => {
    console.log('Fetching daily report for:', reportDate);
    try {
      const res = await fetch(`/api/report/daily?date=${reportDate}`);
      if (!res.ok) throw new Error(`Failed to fetch report: ${res.status}`);
      const data = await res.json();
      console.log('Daily report data:', data);
      setReport(data);
    } catch (err: unknown) {
      console.error('Daily report error:', err);
      alert('Failed to fetch daily report: ' + (err instanceof Error ? err.message : 'Unknown error'));
    }
  };

  return (
    <div className="App">
      <h1>Barrel Tracker</h1>
      <div>
        <h2>Receive Inventory</h2>
        {/* unchanged form */}
        <select value={form.account} onChange={e => setForm({ ...form, account: e.target.value })}>...</select>
        <select value={form.type} onChange={e => setForm({ ...form, type: e.target.value })}>...</select>
        <input type="number" placeholder="Quantity" value={form.quantity} onChange={e => setForm({ ...form, quantity: e.target.value })} />
        <input type="number" placeholder="Proof (if Spirits)" value={form.proof} onChange={e => setForm({ ...form, proof: e.target.value })} />
        <input type="text" placeholder="Source" value={form.source} onChange={e => setForm({ ...form, source: e.target.value })} />
        <input type="text" placeholder="DSP Number" value={form.dspNumber} onChange={e => setForm({ ...form, dspNumber: e.target.value })} />
        <input type="date" value={form.receivedDate} onChange={e => setForm({ ...form, receivedDate: e.target.value })} />
        <button onClick={handleReceive}>Receive</button>
      </div>
      <div>
        <h2>Inventory</h2>
        <table>{/* unchanged table */}</table>
      </div>
      <div>
        <h2>Reports</h2>
        <div>
          <input
            type="month"
            value={reportMonth}
            onChange={e => setReportMonth(e.target.value)}
          />
          <button onClick={fetchMonthlyReport}>Fetch Monthly Report</button>
        </div>
        <div>
          <input
            type="date"
            value={reportDate}
            onChange={e => setReportDate(e.target.value)}
          />
          <button onClick={fetchDailyReport}>Fetch Daily Report</button>
        </div>
        {report ? (
          <div>
            <h3>{report.month ? `Monthly Report: ${report.month}` : `Daily Report: ${report.date}`}</h3>
            <p>Total Received: {report.totalReceived} PG</p>
            <p>Total Processed: {report.totalProcessed} PG</p>
            {report.totalMoved !== undefined && <p>Total Moved: {report.totalMoved} PG</p>}
            {report.totalRemoved !== undefined && <p>Total Removed: {report.totalRemoved} PG</p>}
            {report.transactions && (
              <ul>
                {report.transactions.map((t, i) => (
                  <li key={i}>{`${t.action}: ${t.proofGallons} PG (${t.type}) on ${t.date}`}</li>
                ))}
              </ul>
            )}
          </div>
        ) : (
          <p>Select a month or date and fetch a report.</p>
        )}
      </div>
    </div>
  );
};

export default App;
